@app.route("/users/<user_id>", methods=["PUT"])
def update_user_profile(user_id):
    oid = parse_object_id(user_id)
    if not oid:
        return jsonify({"error": "Invalid user id"}), 400

    data = request.get_json(silent=True) or {}
    allowed_fields = {"username", "email", "full_name", "bio", "roles", "preferences"}
    update_fields = {k: v for k, v in data.items() if k in allowed_fields}

    if "email" in update_fields and isinstance(update_fields["email"], str):
        update_fields["email"] = update_fields["email"].lower().strip()
    if "username" in update_fields and isinstance(update_fields["username"], str):
        update_fields["username"] = update_fields["username"].strip()
    if "full_name" in update_fields and isinstance(update_fields["full_name"], str):
        update_fields["full_name"] = update_fields["full_name"].strip()
    if "bio" in update_fields and isinstance(update_fields["bio"], str):
        update_fields["bio"] = update_fields["bio"].strip()

    if not update_fields:
        return jsonify({"error": "No valid fields provided for update"}), 400

    update_fields["updated_at"] = datetime.utcnow()

