@app.route("/documents", methods=["GET"])
def query_documents():
    query = {}

    author_id = request.args.get("author_id")
    status = request.args.get("status")
    tag = request.args.get("tag")
    title = request.args.get("title")
    limit = min(int(request.args.get("limit", 20)), 100)
    skip = max(int(request.args.get("skip", 0)), 0)
    sort_by = request.args.get("sort_by", "created_at")
    sort_order = request.args.get("sort_order", "desc")

    if author_id:
        author_oid = parse_object_id(author_id)
        if not author_oid:
            return jsonify({"error": "Invalid author_id"}), 400
        query["author_id"] = author_oid

    if status:
        query["status"] = status

    if tag:
        query["tags"] = tag

    if title:
        query["title"] = {"$regex": title, "$options": "i"}

    direction = DESCENDING if sort_order.lower() == "desc" else ASCENDING

    try:
        docs = list(
            documents_collection.find(query)
            .sort(sort_by, direction)
            .skip(skip)
            .limit(limit)
        )
        total = documents_collection.count_documents(query)
        return jsonify({
            "total": total,
            "count": len(docs),
            "items": [serialize_document(doc) for doc in docs]
        }), 200
    except PyMongoError as e:
        return jsonify({"error": str(e)}), 500
    except ValueError:
        return jsonify({"error": "Invalid pagination parameters"}), 400


