@app.route("/analytics/content-summary", methods=["GET"])
def content_summary():
    pipeline = [
        {
            "$facet": {
                "status_counts": [
                    {
                        "$group": {
                            "_id": "$status",
                            "count": {"$sum": 1}
                        }
                    },
                    {
                        "$project": {
                            "_id": 0,
                            "status": "$_id",
                            "count": 1
                        }
                    }
                ],
                "tag_counts": [
                    {"$unwind": "$tags"},
                    {
                        "$group": {
                            "_id": "$tags",
                            "count": {"$sum": 1}
                        }
                    },
                    {
                        "$project": {
                            "_id": 0,
                            "tag": "$_id",
                            "count": 1
                        }
                    },
                    {"$sort": {"count": -1}},
                    {"$limit": 10}
                ],
                "totals": [
                    {
                        "$group": {
                            "_id": None,
                            "total_documents": {"$sum": 1}
                        }
                    },
                    {
                        "$project": {
                            "_id": 0,
                            "total_documents": 1
                        }
                    }
                ]
            }
        }
    ]

    try:
        result = list(documents_collection.aggregate(pipeline))
        summary = result[0] if result else {"status_counts": [], "tag_counts": [], "totals": []}
        return jsonify(serialize_document(summary)), 200
    except PyMongoError as e:
        return jsonify({"error": str(e)}), 500


